package be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst;

import be.schaubroeck.lpb.rkm.rekenmotor.TussenkomstManager;
import be.schaubroeck.lpb.rkm.rekenmotor.comparator.IdentifiableOrdering;
import be.schaubroeck.lpb.rkm.rekenmotor.comparator.ManueleTussenkomstComparator;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.OpdrachtAardKodeExtensieKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.OpperAkeRegimeBedragTypeKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.HashMoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.tools.ManueleTussenkomst;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.SleutelTussenkomstHoofd;
import be.schaubroeck.lpb.tools.comparator.SleutelTussenkomstHoofdComparator;
import be.schaubroeck.util.persistence.Identifiable;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.SortedSetMultimap;
import com.google.common.collect.TreeMultimap;

import java.util.Collection;
import java.util.Collections;
import java.util.SortedSet;
import java.util.TreeSet;

public class TussenkomstManagerImp implements TussenkomstManager {

    private SortedSet<ManueleTussenkomst> persoonsElementen = new TreeSet<>(ManueleTussenkomstComparator.DEFAULT);
    private SortedSetMultimap<Opdracht, ManueleTussenkomst> opdrachtsElementenMap = createSortedSetMultiMap();
    private SortedSetMultimap<Opper, ManueleTussenkomst> opperElementenMap = createSortedSetMultiMap();

    private SortedSet<SleutelTussenkomstHoofd> sleutelTussenkomsten = SleutelTussenkomstHoofdComparator.createSortedSet();

    private Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> tussenkomstOpZeroMap = HashMultimap.create();
    private Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> sleutelTussenkomstOpZeroMap = HashMultimap.create();

    private MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten = new HashMoneyMap<>();

    @Override
    public Collection<ManueleTussenkomst> getPersoonsElementen() {
        return Collections.unmodifiableSet(persoonsElementen);
    }

    private SortedSet<ManueleTussenkomst> getPersoonsElementenIntern() {
        return persoonsElementen;
    }

    @Override
    public Collection<ManueleTussenkomst> getOpdrachtsElementen(Opdracht opdracht) {
        return Collections.unmodifiableSet(getOpdrachtsElementenIntern(opdracht));
    }

    private SortedSet<ManueleTussenkomst> getOpdrachtsElementenIntern(Opdracht opdracht) {
        return opdrachtsElementenMap.get(opdracht);
    }

    @Override
    public Collection<ManueleTussenkomst> getOpperElementen(Opper opper) {
        return Collections.unmodifiableSet(getOpperElementenIntern(opper));
    }

    private SortedSet<ManueleTussenkomst> getOpperElementenIntern(Opper opper) {
        return opperElementenMap.get(opper);
    }

    @Override
    public void addTussenkomst(ManueleTussenkomst manueleTussenkomst, Opper opper) {
        getPersoonsElementenIntern().add(manueleTussenkomst);
        getOpdrachtsElementenIntern(opper.getOpdracht()).add(manueleTussenkomst);
        getOpperElementenIntern(opper).add(manueleTussenkomst);
    }

    @Override
    public Collection<SleutelTussenkomstHoofd> getSleutelTussenkomsten() {
        return Collections.unmodifiableSet(sleutelTussenkomsten);
    }

    @Override
    public void addSleutelTussenkomst(SleutelTussenkomstHoofd sleutelTussenkomst) {
        sleutelTussenkomsten.add(sleutelTussenkomst);
    }

    @Override
    public void tussenkomstOpZeroProperty(OpdrachtAardKodeExtensieKey sleutel, MoneyKey moneyKey) {
        tussenkomstOpZeroMap.put(sleutel, moneyKey);
    }

    @Override
    public void sleutelTussenkomstOpZeroProperty(OpdrachtAardKodeExtensieKey sleutel, MoneyKey moneyKey) {
        sleutelTussenkomstOpZeroMap.put(sleutel, moneyKey);
    }

    @Override
    public Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> getTussenkomstOpZeroMap() {
        return tussenkomstOpZeroMap;
    }

    @Override
    public Multimap<OpdrachtAardKodeExtensieKey, MoneyKey> getSleutelTussenkomstOpZeroMap() {
        return sleutelTussenkomstOpZeroMap;
    }

    public static SortedSet<ManueleTussenkomst> createSortedSet() {
        return new TreeSet<>(ManueleTussenkomstComparator.DEFAULT);
    }

    public static <T extends Identifiable> SortedSetMultimap<T, ManueleTussenkomst> createSortedSetMultiMap() {
        return TreeMultimap.create(new IdentifiableOrdering<>(), ManueleTussenkomstComparator.DEFAULT);
    }

    @Override
    public MoneyMap<OpperAkeRegimeBedragTypeKey> getToegepasteTussenkomsten() {
        return toegepasteTussenkomsten;
    }

    @Override
    public void setToegepasteTussenkomsten(MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten) {
        this.toegepasteTussenkomsten = toegepasteTussenkomsten;
    }
}
